// Mode: Run Once for All Items — JavaScript
// Robust JSON extractor + "N/A" coercion + diagnostics
// Updated to PRESERVE ARRAYS for skills, move soft skills to good_to_have,
// and add JOB-AGNOSTIC keyword atomization for universal matching.

const NA = 'N/A';
const DROP_EMPTY_ROWS = false;

// ---------- JSON extraction helpers ----------
function stripCodeFences(s) {
  return s.replace(/```(?:json)?/gi, '').replace(/```/g, '');
}
function stripPreamble(s) {
  const firstBrace = s.indexOf('{');
  const firstBracket = s.indexOf('[');
  let idx = -1;
  if (firstBrace === -1 && firstBracket === -1) return s;
  if (firstBrace === -1) idx = firstBracket;
  else if (firstBracket === -1) idx = firstBrace;
  else idx = Math.min(firstBrace, firstBracket);
  return s.slice(idx);
}
function replaceSmartQuotes(s) {
  return s
    .replace(/[\u201C\u201D\u2033]/g, '"')
    .replace(/[\u2018\u2019\u2032]/g, "'");
}
function unescapeIfQuotedJsonString(s) {
  const t = String(s).trim();
  const looksQuoted = (t.startsWith('"') && t.endsWith('"')) || (t.startsWith("'") && t.endsWith("'"));
  if (!looksQuoted) return { ok:false };
  try {
    const once = JSON.parse(t);
    if (typeof once === 'string') return { ok:true, value: once };
    return { ok:false };
  } catch { return { ok:false }; }
}
function tryParse(s) {
  try { return { ok:true, value: JSON.parse(s) }; }
  catch (e) { return { ok:false, error: e.message }; }
}
function extractJsonFromText(s) {
  if (typeof s !== 'string') return { ok:false, why:'not_string' };
  let txt = stripCodeFences(replaceSmartQuotes(s)).trim();
  if (!txt.startsWith('{') && !txt.startsWith('[')) txt = stripPreamble(txt);

  let p = tryParse(txt);
  if (p.ok) return p;

  const iBrace = txt.indexOf('{'), jBrace = txt.lastIndexOf('}');
  if (iBrace !== -1 && jBrace !== -1 && jBrace > iBrace) {
    p = tryParse(txt.slice(iBrace, jBrace + 1));
    if (p.ok) return p;
  }
  const iBracket = txt.indexOf('['), jBracket = txt.lastIndexOf(']');
  if (iBracket !== -1 && jBracket !== -1 && jBracket > iBracket) {
    p = tryParse(txt.slice(iBracket, jBracket + 1));
    if (p.ok) return p;
  }

  const unq = unescapeIfQuotedJsonString(txt);
  if (unq.ok) {
    const inner = stripCodeFences(replaceSmartQuotes(unq.value)).trim();
    const inner2 = (!inner.startsWith('{') && !inner.startsWith('[')) ? stripPreamble(inner) : inner;
    let q = tryParse(inner2);
    if (q.ok) return q;
    const ib = inner2.indexOf('{'), jb = inner2.lastIndexOf('}');
    if (ib !== -1 && jb !== -1 && jb > ib) {
      q = tryParse(inner2.slice(ib, jb + 1));
      if (q.ok) return q;
    }
  }
  return { ok:false, why:'json_not_found_or_invalid' };
}

// ---------- Coercion + normalization helpers ----------
const isEmptyStr = v => (typeof v === 'string' && v.trim() === '');
function toNA(v) {
  return (v === undefined || v === null || isEmptyStr(v)) ? NA : String(v);
}
function numOrNA(v) {
  return (v === 0 || (typeof v === 'number' && !Number.isNaN(v))) ? v
       : (v === null || v === undefined || v === '' ? NA : v);
}
function boolOrNA(v) { return (v === true || v === false) ? v : NA; }

// Keep arrays (no join); split strings ONLY on , ; | and preserve spaces inside tokens
function toArrayKeep(x) {
  if (x == null) return [];
  if (Array.isArray(x)) return x.map(s => String(s));
  if (typeof x === 'object') return Object.values(x).map(String);
  return String(x).split(/[;,|]/).map(s => s.trim()).filter(Boolean);
}

// Minimal, job-agnostic canonicalization (NO domain lists)
const CANON = {
  'google tag management': 'google tag manager',
  'google tag manager': 'google tag manager',
  gtm: 'google tag manager',
  'ms excel': 'excel',
  'microsoft excel': 'excel',
  ga4: 'google analytics',
  'google analytics 4': 'google analytics'
};
function normSkill(s) {
  const base = String(s).toLowerCase().trim()
    .replace(/[()]/g, '')
    .replace(/[_\-]+/g, ' ')      // unify hyphen/underscore to space
    .replace(/\s+/g, ' ');
  return CANON[base] || base;
}
function uniq(a) { return [...new Set((a || []).filter(Boolean))]; }

// Soft skills detector (generic, NOT domain-specific)
const SOFT_RE = /\b(communication|storytelling|collaboration|leadership|stakeholder(?: management)?|mentorship|coaching|team(?:\s*)work|presentation|interpersonal)\b/;
function isSoftSkill(token) {
  return SOFT_RE.test(String(token).toLowerCase());
}

// ---------- UNIVERSAL ATOMIZER v1 (job-agnostic) ----------
const STOP = new Set([
  "a","an","the","and","or","of","to","in","for","with","on","as","by","from","at","into",
  "such","that","this","those","these","their","our","your","his","her","its","is","are",
  "be","being","been","will","shall","may","might","can","could","should","would",
  "ability","capable","capability","skills","skill","proficiency","experience",
  "experienced","knowledge","understanding","familiarity","proven","track","record","using",
  "use","utilize","including","etc","and/or","per","via","across","within","about"
]);

const DELEADERS = [
  /^(\d+\+?\s*years?|years?)\b.*?\b(in|with|of)\b\s*/i,
  /^(hands[-\s]?on|strong|solid|deep|working)\s+/i,
  /^(proven|demonstrated)\s+(ability|experience)\s+(to|in|with)\s+/i,
  /^(ability|experience|knowledge|understanding)\s+(to|of|with|in)\s+/i
];

function cleanPhrase(s){
  let t = String(s||"").toLowerCase().trim();
  DELEADERS.forEach(re => t = t.replace(re,""));
  // keep tech punctuation; drop brackets/quotes
  t = t.replace(/[\u2018\u2019'"]/g,"")
       .replace(/[()]/g," ")
       .replace(/[,;]|\/+/g," ")
       .replace(/\s+/g," ")
       .trim();
  return t;
}

function tokenize(s){
  const words = s.split(/\s+/).filter(w => w && !STOP.has(w));
  return words;
}

function ngrams(words, maxN=3){
  const out = [];
  for (let n=1;n<=maxN;n++){
    for (let i=0;i<=words.length-n;i++){
      out.push(words.slice(i,i+n).join(" "));
    }
  }
  return out;
}

function variants(atom){
  const v = new Set();
  const spaced = atom.trim();
  if (!spaced) return [];
  v.add(spaced);                          // "bill of materials"
  v.add(spaced.replace(/-/g," "));        // hyphen → space
  v.add(spaced.replace(/[\s-]/g,""));     // collapse: "billofmaterials"
  const letters = spaced.split(/\s+/).map(w => w[0]).join("");
  if (letters.length >= 2) v.add(letters); // acronym "bom"
  return Array.from(v);
}

function keepToken(t){
  // keep if alnum len>=2, or contains techy chars or digits
  return /[a-z0-9]/.test(t) && (t.length>=2 || /[#+.\d]/.test(t));
}

function atomizeArray(arr){
  const out = new Set();
  for (const raw of (arr||[])){
    const cleaned = cleanPhrase(raw);
    if (!cleaned) continue;
    const toks = tokenize(cleaned);
    const grams = ngrams(toks, 3);
    for (const g of grams){
      for (const v of variants(g)){
        const t = v.replace(/\s+/g," ").trim();
        if (keepToken(t)) out.add(t);
      }
    }
  }
  return Array.from(out);
}

// ---------- Contract coerce ----------
function coerceRecord(obj) {
  let rec = obj;

  if (rec?.message?.content && typeof rec.message.content === 'string') {
    const parsed = extractJsonFromText(rec.message.content);
    if (parsed.ok) rec = parsed.value;
    else return { rec:null, reason: 'parse_failed_message.content:'+parsed.why };
  } else if (typeof rec?.content === 'string') {
    const parsed = extractJsonFromText(rec.content);
    if (parsed.ok) rec = parsed.value;
    else return { rec:null, reason: 'parse_failed_content:'+parsed.why };
  } else if (rec && typeof rec === 'object') {
    // ok
  } else {
    return { rec:null, reason:'no_payload' };
  }

  const keys = [
    'job_id','job_number','company','department','job_title',
    'location_city','location_state_province','location_country',
    'remote','min_year_req','required_skills','good_to_have',
    'raw_json','njd_must_have_skills','njd_nice_to_have_skills','njd_tools_and_tech'
  ];
  const hasAny = keys.some(k => Object.prototype.hasOwnProperty.call(rec, k));
  if (!hasAny) return { rec:null, reason:'missing_contract_keys' };

  return { rec, reason:'ok' };
}

// ---------- Main ----------
const rows = [];

for (const it of items) {
  const j = it.json ?? {};
  const { rec, reason } = coerceRecord(j);

  if (!rec) {
    const row = {
      __status: 'empty',
      __reason: reason,

      job_id: NA, job_number: NA, company: NA, department: NA, job_title: NA,
      location_city: NA, location_state_province: NA, location_country: NA,
      remote: NA, date_posted: NA, pay_currency: NA, pay_min: NA, pay_max: NA, pay_period: NA,
      min_year_req: NA, required_education: NA, preferred_education: NA, role_level: NA,

      // arrays
      required_skills: [],
      required_qualifications: [],
      responsibilities: [],
      good_to_have: [],

      // njd block
      njd_remote_policy: NA, njd_onsite_requirement: NA, njd_onsite_offices: [],
      njd_employment_type: NA, njd_comp_currency: NA, njd_comp_min: NA, njd_comp_max: NA,
      njd_comp_period: NA, njd_comp_structure_notes: [],
      njd_years_experience_min: NA,
      njd_must_have_skills: [], njd_nice_to_have_skills: [], njd_tools_and_tech: [], njd_domain_experience: [],
      njd_benefits: [], njd_keywords: [], njd_eq_eo_statement: NA,

      // NEW keywords (empty on error)
      njd_required_keywords: [],
      njd_preferred_keywords: [],

      __hard_required_ok: false,
      __missing_required: 'company | job_title | required_skills'
    };
    if (!DROP_EMPTY_ROWS) rows.push({ json: row });
    continue;
  }

  const njd = rec?.raw_json?.normalized_jd ?? {};

  // ---- skills as arrays, normalized, deduped; spaces preserved ----
  let required_skills_arr = uniq(
    toArrayKeep(rec.required_skills ?? rec.njd_must_have_skills ?? njd.must_have_skills).map(normSkill)
  );
  let good_to_have_arr = uniq(
    toArrayKeep(rec.good_to_have ?? rec.njd_nice_to_have_skills ?? njd.nice_to_have_skills).map(normSkill)
  );
  const tools_and_tech_arr = uniq(
    toArrayKeep(rec.tools_and_tech ?? rec.njd_tools_and_tech ?? njd.tools_and_tech).map(normSkill)
  );

  // ---- RE-BUCKET: move obvious soft skills out of required into good_to_have (generic) ----
  const softInRequired = required_skills_arr.filter(isSoftSkill);
  if (softInRequired.length) {
    required_skills_arr = required_skills_arr.filter(s => !isSoftSkill(s));
    good_to_have_arr = uniq(good_to_have_arr.concat(softInRequired));
  }

  // Optional cap to keep required concise
  if (required_skills_arr.length > 20) {
    required_skills_arr = required_skills_arr.slice(0, 20);
  }

  // ---- NEW: job-agnostic keyword atoms (for universal matching) ----
  const required_keywords = atomizeArray(
    required_skills_arr.length ? required_skills_arr : toArrayKeep(rec.required_qualifications)
  );
  const preferred_keywords = atomizeArray(good_to_have_arr);

  // ----- Row build -----
  const row = {
    __status: 'ok',
    __reason: reason,

    job_id: toNA(rec.job_id ?? rec.id ?? rec.jobid),
    job_number: toNA(rec.job_number),
    company: toNA(rec.company),
    department: toNA(rec.department),
    job_title: toNA(rec.job_title ?? rec.title),
    location_city: toNA(rec.location_city ?? rec.city),
    location_state_province: toNA(rec.location_state_province ?? rec.state),
    location_country: toNA(rec.location_country ?? rec.country),
    remote: boolOrNA(rec.remote),
    date_posted: toNA(rec.date_posted),
    pay_currency: toNA(rec.pay_currency),
    pay_min: numOrNA(rec.pay_min),
    pay_max: numOrNA(rec.pay_max),
    pay_period: toNA(rec.pay_period),
    min_year_req: numOrNA(rec.min_year_req ?? rec.njd_years_experience_min),
    required_education: toNA(rec.required_education),
    preferred_education: toNA(rec.preferred_education),
    role_level: toNA(rec.role_level),

    // arrays preserved
    required_skills: required_skills_arr,
    required_qualifications: toArrayKeep(rec.required_qualifications),
    responsibilities: toArrayKeep(rec.responsibilities),
    good_to_have: good_to_have_arr,

    // njd block (keep arrays where applicable)
    njd_remote_policy: toNA(njd?.location?.remote_policy ?? rec.njd_remote_policy),
    njd_onsite_requirement: toNA(njd?.location?.onsite_requirement ?? rec.njd_onsite_requirement),
    njd_onsite_offices: toArrayKeep(njd?.location?.onsite_offices ?? rec.njd_onsite_offices),

    njd_employment_type: toNA(njd?.employment?.type ?? rec.njd_employment_type),
    njd_comp_currency: toNA(njd?.employment?.pay_currency ?? rec.njd_comp_currency),
    njd_comp_min: numOrNA(njd?.employment?.pay_min ?? rec.njd_comp_min),
    njd_comp_max: numOrNA(njd?.employment?.pay_max ?? rec.njd_comp_max),
    njd_comp_period: toNA(njd?.employment?.pay_period ?? rec.njd_comp_period),
    njd_comp_structure_notes: toArrayKeep(njd?.employment?.comp_structure_notes ?? rec.njd_comp_structure_notes),

    njd_years_experience_min: numOrNA(njd?.years_experience_min ?? rec.njd_years_experience_min),

    njd_must_have_skills: required_skills_arr,           // mirror for compatibility
    njd_nice_to_have_skills: good_to_have_arr,
    njd_tools_and_tech: tools_and_tech_arr,
    njd_domain_experience: toArrayKeep(njd?.domain_experience ?? rec.njd_domain_experience),

    njd_benefits: toArrayKeep(njd?.benefits ?? rec.njd_benefits),

    // refreshed: union of atoms + tools (ensures matchable keywords)
    njd_keywords: uniq([
      ...required_keywords,
      ...preferred_keywords,
      ...tools_and_tech_arr
    ]),

    // NEW fields
    njd_required_keywords: required_keywords,
    njd_preferred_keywords: preferred_keywords,

    njd_eq_eo_statement: toNA(njd?.eq_eo_statement ?? rec.njd_eq_eo_statement)
  };

  const missingRequired = [];
  if (row.company === NA) missingRequired.push('company');
  if (row.job_title === NA) missingRequired.push('job_title');
  if (!row.required_skills.length) missingRequired.push('required_skills');
  row.__hard_required_ok = missingRequired.length === 0;
  row.__missing_required = missingRequired.length ? missingRequired.join(' | ') : '';

  rows.push({ json: row });
}

return rows;

/**
 * normalize_cand — Candidate LLM Output Validator & Normalizer (n8n Function/Code node)
 * Works in BOTH modes: Run Once for All Items or Run Once for Each Item.
 * - Robustly extracts a JSON ARRAY from LLM outputs (message.content, choices[0].message.content, etc.)
 * - Emits normalized cand_* fields for downstream logic
 * - Adds candidate_direct_skills, candidate_inferred_skills, candidate_education, candidate_soft_skills (arrays)
 * - Removes soft-skill bleed from inferred (inferred -= soft)
 * - Preserves upstream fields (non-destructive) and promotes meta identifiers
 * - Keeps cand_skills for backward compatibility (union of direct+inferred)
 */

const PRESERVE_UPSTREAM = true; // keep all existing item.json fields (non-destructive merge)

// ---------------- allowed keys (extended, but keeps your original) ----------------
const ALLOWED_KEYS = [
  // legacy/base fields (kept for compatibility)
  "name","email","phone",
  "location_city","location_state_province","location_country",
  "remote","total_years_experience","highest_degree",
  "latest_title","latest_company",
  "skills_text","titles","achievements",
  "raw_json",

  // normalized fields used downstream
  "cand_name","cand_email",
  "cand_location_city","cand_location_state_province","cand_location_country",
  "cand_remote","cand_total_years_experience","cand_experience_level",
  "cand_skills",

  // NEW: explicit arrays & meta + promoted identifiers
  "candidate_direct_skills","candidate_inferred_skills","candidate_education","candidate_soft_skills",
  "meta","cand_index",
  "candidate_id","candidate_email","candidate_phone","candidate_name",
  "candidate_linkedin","candidate_github","candidate_location"
];

// ---------------- helpers: parsing & cleanup ----------------
function stripCodeFences(s){ return s.replace(/```(?:json)?/gi,'').replace(/```/g,''); }
function replaceSmartQuotes(s){ return s.replace(/[\u201C\u201D\u2033]/g,'"').replace(/[\u2018\u2019\u2032]/g,"'"); }
function stripPreamble(s){
  const i1=s.indexOf('['), i2=s.indexOf('{'); let idx=-1;
  if(i1===-1 && i2===-1) return s;
  if(i1===-1) idx=i2; else if(i2===-1) idx=i1; else idx=Math.min(i1,i2);
  return s.slice(idx);
}
function tryParse(s){ try{ return {ok:true, value: JSON.parse(s)} }catch(e){ return {ok:false, error:e.message} } }
function unescapeIfQuotedJsonString(s){
  const t=String(s).trim();
  const looksQuoted=(t.startsWith('"')&&t.endsWith('"'))||(t.startsWith("'")&&t.endsWith("'"));
  if(!looksQuoted) return {ok:false};
  try{ const once=JSON.parse(t); if(typeof once==='string') return {ok:true, value: once}; return {ok:false}; }
  catch{ return {ok:false}; }
}
function extractJsonArray(s){
  if(typeof s!=='string') return {ok:false, why:'not_string'};
  let txt=stripCodeFences(replaceSmartQuotes(s)).trim();
  if(!txt.startsWith('[') && !txt.startsWith('{')) txt=stripPreamble(txt);

  // direct parse
  let p=tryParse(txt);
  if(p.ok) return Array.isArray(p.value) ? {ok:true, value:p.value} : {ok:false, why:'not_array'};

  // crop to outermost array
  const i=txt.indexOf('['), j=txt.lastIndexOf(']');
  if(i!==-1 && j!==-1 && j>i){
    p=tryParse(txt.slice(i,j+1));
    if(p.ok) return Array.isArray(p.value) ? {ok:true, value:p.value} : {ok:false, why:'not_array'};
  }

  // quoted JSON string containing array
  const unq=unescapeIfQuotedJsonString(txt);
  if(unq.ok){
    const inner=stripCodeFences(replaceSmartQuotes(unq.value)).trim();
    const inner2=(!inner.startsWith('[')&&!inner.startsWith('{'))?stripPreamble(inner):inner;
    let q=tryParse(inner2);
    if(q.ok) return Array.isArray(q.value) ? {ok:true, value:q.value} : {ok:false, why:'not_array'};
    const i2=inner2.indexOf('['), j2=inner2.lastIndexOf(']');
    if(i2!==-1 && j2!==-1 && j2>i2){
      q=tryParse(inner2.slice(i2,j2+1));
      if(q.ok) return Array.isArray(q.value) ? {ok:true, value:q.value} : {ok:false, why:'not_array'};
    }
  }
  return {ok:false, why:'json_array_not_found'};
}

function isNullish(v){ return v===null || v===undefined; }
function passStringOrNull(v){ if(isNullish(v)) return null; const s=String(v).trim(); return s===''?null:s; }
function toLowerNoWhitespaceEmail(v){
  if(isNullish(v)) return null;
  const s=String(v).toLowerCase().replace(/[\s\r\n\u00A0\u200B\u200C\u200D\u2028\u2029\uFEFF]/g,'');
  return s.includes('@') ? s : null;
}
function toBoolOrNull(v){
  if(v===true||v===false) return v;
  if(isNullish(v)) return null;
  const s=String(v).trim().toLowerCase();
  if(s==='true' || s==='yes' || s==='hybrid') return true;
  if(s==='false' || s==='no' || s==='onsite' || s==='office') return false;
  return null;
}
function toNumOrNull(v){
  if(isNullish(v) || v==='') return null;
  if(typeof v==='number' && !Number.isNaN(v)) return v;
  const m=String(v).match(/-?\d+(\.\d+)?/);
  return m ? parseFloat(m[0]) : null;
}
function ensureString(v, joiner=', '){
  if(isNullish(v)) return '';
  if(Array.isArray(v)){
    const clean=v.map(x=>String(x).trim()).filter(x=>x!=='');
    return clean.join(joiner);
  }
  return String(v);
}
function onlyAllowedKeys(obj){
  const out={};
  for(const k of ALLOWED_KEYS){ if(Object.prototype.hasOwnProperty.call(obj,k)) out[k]=obj[k]; }
  return out;
}

// ---------------- skills normalization ----------------
function toArrayKeep(x){
  if (x == null) return [];
  if (Array.isArray(x)) return x.map(String);
  if (typeof x === 'object') return Object.values(x).map(String);
  return String(x).split(/[;,|]/).map(s=>s.trim()).filter(Boolean);
}
const CANON = {
  'google tag management': 'google tag manager',
  'google tag manager': 'google tag manager',
  gtm: 'google tag manager',
  'ms excel': 'excel',
  'microsoft excel': 'excel',
  'ga4': 'google analytics',
  'google analytics 4': 'google analytics',
  'sql server': 'sql'
};
function normSkill(s){
  const base = String(s).toLowerCase().trim()
    .replace(/[()]/g,'')
    .replace(/[_\-]+/g,' ')
    .replace(/\s+/g,' ');
  return CANON[base] || base;
}
function uniq(a){ return [...new Set((a||[]).filter(Boolean))]; }

// Soft skills detector (generic)
const SOFT_RE = /\b(communication|storytelling|collaboration|leadership|stakeholder(?: management)?|mentorship|coaching|team(?:\s*)work|presentation|interpersonal)\b/;
function isSoftSkill(token){ return SOFT_RE.test(String(token).toLowerCase()); }

// ---------------- level inference ----------------
function inferLevel(years){
  const y = Number(years)||0;
  if (y >= 10) return 'lead';
  if (y >= 6)  return 'senior';
  if (y >= 3)  return 'mid';
  return 'junior';
}

// ---------------- LLM text resolver ----------------
function resolveLlmText(payload){
  const direct = ['text','content','data','body','output'];
  for (const k of direct){ if (typeof payload[k] === 'string' && payload[k].trim() !== '') return payload[k]; }
  if (payload.message){
    if (typeof payload.message.content === 'string' && payload.message.content.trim() !== '') return payload.message.content;
    if (Array.isArray(payload.message.content)){
      const parts = payload.message.content.map(p => {
        if (typeof p === 'string') return p;
        if (p && typeof p.text === 'string') return p.text;
        if (p && typeof p.content === 'string') return p.content;
        return '';
      }).filter(Boolean);
      if (parts.length) return parts.join('\n');
    }
  }
  if (payload.choices && Array.isArray(payload.choices) && payload.choices[0]?.message?.content){
    return payload.choices[0].message.content;
  }
  return null;
}

// ---------------- record normalizer ----------------
function normalizeRecord(r, fallbackIndex){
  // meta (may contain identifiers and index)
  const meta = (r && typeof r.meta === 'object' && r.meta !== null) ? { ...r.meta } : {};
  if (typeof meta.index !== 'number') meta.index = (typeof fallbackIndex === 'number') ? fallbackIndex : 0;

  // base fields from LLM (legacy compatibility)
  const base = {
    name: passStringOrNull(r.name ?? meta.name),
    email: toLowerNoWhitespaceEmail(r.email ?? meta.email),
    phone: passStringOrNull(r.phone ?? meta.phone),

    location_city: passStringOrNull(r.location_city ?? (meta.location || null)),
    location_state_province: passStringOrNull(r.location_state_province),
    location_country: passStringOrNull(r.location_country),

    remote: toBoolOrNull(r.remote),
    total_years_experience: toNumOrNull(r.total_years_experience),

    highest_degree: (()=>{
      const hd = (r.highest_degree==null? null : String(r.highest_degree).toLowerCase().trim());
      if (hd==="bachelor's"||hd==='bachelors'||hd==='bachelor') return "bachelor's";
      if (hd==="master's"||hd==='masters'||hd==='master') return "master's";
      if (hd==='phd'||hd==='doctorate') return "phd";
      return null;
    })(),

    latest_title: passStringOrNull(r.latest_title),
    latest_company: passStringOrNull(r.latest_company),

    skills_text: ensureString(r.skills_text, ', '),
    titles: r.latest_title ? String(r.latest_title) : '',
    achievements: ensureString(r.achievements, '; ')
  };

  // NEW explicit arrays from LLM (preferred)
  const directLLM   = uniq(toArrayKeep(r.candidate_direct_skills).map(normSkill));
  const inferredLLM = uniq(toArrayKeep(r.candidate_inferred_skills).map(normSkill));
  const educationLLM= uniq(toArrayKeep(r.candidate_education).map(s => String(s).toLowerCase().trim()));
  const softLLM     = uniq(toArrayKeep(r.candidate_soft_skills).map(normSkill));

  // Remove soft-skill bleed from inferred and filter generic soft tokens
  const softSet = new Set(softLLM);
  const inferredClean = inferredLLM.filter(x => !softSet.has(x) && !isSoftSkill(x));

  // Fallback skills if LLM didn't provide explicit arrays
  const fallbackSources = [
    ...(Array.isArray(r.skills) ? r.skills : []),
    ...(Array.isArray(r.keywords) ? r.keywords : []),
    ...toArrayKeep(r.skills_text)
  ];
  const fallbackSkills = uniq(fallbackSources.map(normSkill));

  // Compose cand_skills for backward compatibility (union of direct + inferred; if empty, use fallback)
  const cand_skills = uniq(
    (directLLM.length || inferredClean.length) ? directLLM.concat(inferredClean) : fallbackSkills
  );

  // raw_json passthrough + cleanup (legacy)
  const raw = (typeof r.raw_json === 'object' && r.raw_json !== null) ? { ...r.raw_json } : {};
  if (raw.email) raw.email = toLowerNoWhitespaceEmail(raw.email);
  if (raw.remote !== undefined) raw.remote = toBoolOrNull(raw.remote);
  if (typeof raw.location_country === 'string' && raw.location_country.trim()==='') raw.location_country = null;

  // normalized cand_* keys used downstream
  const cand_total_years_experience =
    base.total_years_experience != null ? base.total_years_experience
    : toNumOrNull(raw.total_years_experience);

  const cand_experience_level =
    (typeof r.cand_experience_level === 'string' && r.cand_experience_level) ?
      String(r.cand_experience_level).toLowerCase().trim()
      : inferLevel(cand_total_years_experience);

  // Build normalized record
  const rec = {
    ...base,
    raw_json: raw,

    cand_name: base.name,
    cand_email: base.email,
    cand_location_city: base.location_city,
    cand_location_state_province: base.location_state_province,
    cand_location_country: base.location_country,
    cand_remote: base.remote,
    cand_total_years_experience,
    cand_experience_level,

    // Backward-compat skills
    cand_skills,

    // NEW explicit arrays
    candidate_direct_skills: directLLM,
    candidate_inferred_skills: inferredClean,
    candidate_education: educationLLM,
    candidate_soft_skills: softLLM,

    // meta + promoted identifiers
    meta,
    cand_index: meta.index
  };

  // Promote common identifiers from meta if present (non-invented)
  if (meta.name && !rec.candidate_name)    rec.candidate_name = String(meta.name);
  if (meta.email && !rec.candidate_email)  rec.candidate_email = toLowerNoWhitespaceEmail(meta.email);
  if (meta.phone && !rec.candidate_phone)  rec.candidate_phone = String(meta.phone);
  if (meta.linkedin && !rec.candidate_linkedin) rec.candidate_linkedin = String(meta.linkedin);
  if (meta.github && !rec.candidate_github)     rec.candidate_github   = String(meta.github);
  if (meta.location && !rec.candidate_location) rec.candidate_location = String(meta.location);
  if (meta.candidate_id && !rec.candidate_id)   rec.candidate_id       = String(meta.candidate_id);

  // only keep allowed keys (legacy contract)
  const cleaned = onlyAllowedKeys(rec);
  return cleaned;
}

// ---------------- main ----------------
const INPUT_ITEMS = (typeof items !== 'undefined' && Array.isArray(items)) ? items : [{ json: $json }];
const outItems = [];

for (const it of INPUT_ITEMS) {
  const j = it.json ?? {};
  const text = resolveLlmText(j);

  if (text == null) {
    const baseOut = PRESERVE_UPSTREAM ? { ...(it.json || {}) } : {};
    outItems.push({ json: { ...baseOut, error: true, why: 'no_text_from_llm' } });
    continue;
  }

  const parsed = extractJsonArray(text);
  if (!parsed.ok) {
    const baseOut = PRESERVE_UPSTREAM ? { ...(it.json || {}) } : {};
    outItems.push({
      json: {
        ...baseOut,
        error: true,
        why: 'llm_output_not_json_array',
        detail: parsed.why,
        snippet: String(text).slice(0, 400)
      }
    });
    continue;
  }

  const val = parsed.value;
  for (let i = 0; i < val.length; i++) {
    const r = val[i];
    if (typeof r !== 'object' || r === null) {
      const baseOut = PRESERVE_UPSTREAM ? { ...(it.json || {}) } : {};
      outItems.push({ json: { ...baseOut, error: true, why: 'array_contains_non_object', value: r } });
      continue;
    }

    const cleaned = normalizeRecord(r, i);

    // Append warning for unknown keys in the LLM object (not upstream)
    const unknown = Object.keys(r).filter(k => !ALLOWED_KEYS.includes(k));
    if (unknown.length) cleaned._warning_unknown_keys_stripped = unknown.join(', ');

    // Non-destructive: merge upstream fields unless disabled
    const baseOut = PRESERVE_UPSTREAM ? { ...(it.json || {}) } : {};
    // Avoid carrying giant raw fields if present
    delete baseOut.message;
    delete baseOut.content;
    delete baseOut.data;
    delete baseOut.resume_text;
    delete baseOut.Resume_text;

    outItems.push({ json: { ...baseOut, ...cleaned } });
  }
}

return outItems;

