// one_blub — single item in → single, well-shaped object out
const x = $json;

// helpers
const asArr = v => Array.isArray(v) ? v : (v == null || v === "" ? [] : [String(v)]);
const pick = (...keys) => {
  for (const k of keys) {
    const v = x[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return undefined;
};

// identifiers (with fallbacks)
const job_number   = pick("job_number","njd_job_number","jobNo","jobno","job") || "JD001";
const job_title    = pick("job_title","njd_job_title","title") || "";
const company      = pick("company","njd_company","employer") || "";

const candidate_email = pick("candidate_email","cand_email","email","contact_email") || "";
const candidate_name  = pick("candidate_name","cand_name","name","full_name") || "";
const candidate_phone = pick("candidate_phone","cand_phone","phone","mobile","cell","contact_phone") || "";

const cand_index = (x.cand_index ?? 0);

// stable pair id
const pair_id = x.pair_id || `${job_number}::${candidate_email || candidate_name || `idx_${cand_index}`}`;

// build output (arrays passed through safely)
return {
  // IDs
  pair_id,
  job_number,
  job_title,
  company,

  // Also expose short aliases for downstream nodes that expect cand_* keys
  cand_email: candidate_email,
  cand_name:  candidate_name,
  cand_phone: candidate_phone,

  // Canonical candidate identifiers
  candidate_email,
  candidate_name,
  candidate_phone,

  // JD (pass-through; matcher will normalize further)
  required_skills:       asArr(pick("required_skills","njd_required_skills")),
  good_to_have:          asArr(pick("good_to_have","njd_good_to_have")),
  required_education:    pick("required_education","njd_required_education") || "",
  preferred_education:   pick("preferred_education","njd_preferred_education") || "",

  // Candidate (pass-through; matcher will normalize further)
  candidate_direct_skills:   asArr(x.candidate_direct_skills),
  candidate_inferred_skills: asArr(x.candidate_inferred_skills),
  candidate_soft_skills:     asArr(x.candidate_soft_skills),
  candidate_education:       asArr(x.candidate_education),

  cand_index
};

/**
 * Parse OA adjustment → single compact record (CSV-ready)
 * - Robustly parse OA JSON
 * - Echo identifiers; backfill from current item if OA omitted
 * - Enforce AI-only diffs: req_ai = req_ai \ (req_dir ∪ req_imp); cand_ai = cand_ai \ (cand_dir ∪ cand_imp)
 * - Map quadrant matches to final names
 * - Produce EXACTLY 30 columns with lists joined by "; "
 */

const inItem = $json;

// ---------- helpers ----------
function getAssistantText(j) {
  if (typeof j === "string") return j;
  if (typeof j?.content === "string") return j.content;
  if (Array.isArray(j?.choices) && j.choices[0]?.message?.content) return j.choices[0].message.content;
  if (j?.message?.content) return j.message.content;
  return JSON.stringify(j);
}
function parseOneObject(txt) {
  let s = String(txt || "").trim();
  const m = s.match(/^\s*```(?:json)?\s*([\s\S]*?)\s*```\s*$/i);
  if (m) s = m[1].trim();
  let obj = null;
  if (s.startsWith("{")) obj = JSON.parse(s);
  else {
    const arr = JSON.parse(s);
    obj = Array.isArray(arr) ? arr[0] : arr;
  }
  return obj || {};
}
const norm = (v) => String(v).toLowerCase().trim();
const normArr = a => [...new Set((Array.isArray(a) ? a : []).map(v => norm(v)).filter(Boolean))];
const diff    = (a,b) => {
  const B = new Set(normArr(b));
  return normArr(a).filter(x => !B.has(x));
};
const inter   = (a,b) => {
  const B = new Set(normArr(b));
  return normArr(a).filter(x => B.has(x));
};
const join1 = (arr) => (Array.isArray(arr) ? Array.from(new Set(arr)).join("; ") : String(arr||""));
const uniq  = (a) => Array.from(new Set((a||[]).filter(Boolean)));

// ---------- parse OA ----------
let oa = {};
try {
  oa = parseOneObject(getAssistantText(inItem.__openai_raw || inItem));
} catch (e) {
  oa = {};
}

// ---------- identifiers (echo + backfill) ----------
let pair_id   = oa.pair_id   || inItem.pair_id   || "";
const job_no    = oa.job_number|| inItem.job_number|| inItem.job_no || "";
const job_title = oa.job_title || inItem.job_title || "";
const company   = oa.company   || inItem.company   || "";

const cand_email= oa.candidate_email || inItem.candidate_email || inItem.cand_email || "";
const cand_name = oa.candidate_name  || inItem.candidate_name  || inItem.cand_name  || "";
const cand_phone= oa.candidate_phone || inItem.candidate_phone || inItem.cand_phone || "";

// fallback for pair_id if missing: "N/A::<email>"
if (!pair_id) pair_id = (cand_email ? `N/A::${cand_email}` : "N/A::");

// ---------- buckets (normalize) ----------
const req_dir = normArr(oa.req_dir ?? inItem.required_skills_direct ?? inItem.required_match_direct ?? []);
const req_imp = normArr(oa.req_imp ?? inItem.required_skills_implied ?? inItem.required_match_implied ?? []);
let   req_ai  = normArr(oa.req_ai  ?? inItem.required_skills_ai ?? []);

const cand_dir = normArr(oa.cand_dir ?? inItem.candidate_skills_direct ?? inItem.candidate_direct_skills ?? []);
const cand_imp = normArr(oa.cand_imp ?? inItem.candidate_skills_implied ?? inItem.candidate_inferred_skills ?? []);
let   cand_ai  = normArr(oa.cand_ai  ?? inItem.candidate_skills_ai ?? []);

// Enforce AI-only (no duplication with existing buckets)
const req_base  = uniq([...req_dir, ...req_imp]);
const cand_base = uniq([...cand_dir, ...cand_imp]);
req_ai  = diff(req_ai,  req_base);
cand_ai = diff(cand_ai, cand_base);

// Quadrant-adjusted lists (if OA provided; not strictly required for final columns)
const al = oa.adjusted_lists || {};
const jd_dd = normArr(al.jd_direct_vs_cand_direct || []);
const jd_di = normArr(al.jd_direct_vs_cand_implied || []);
const ji_dd = normArr(al.jd_implied_vs_cand_direct || []);
const ji_di = normArr(al.jd_implied_vs_cand_implied || []);

// Missing (OA view, keep normalized)
const miss_req_dir = normArr(oa.missing_required_direct || []);
const miss_req_imp = normArr(oa.missing_required_implied || []);
const miss_req_ai  = normArr(oa.missing_required_ai || []);

// Counts (source arrays — normalized)
const req_dir_cnt = req_dir.length;
const req_imp_cnt = req_imp.length;
const req_ai_cnt  = req_ai.length;
const cand_dir_cnt= cand_dir.length;
const cand_imp_cnt= cand_imp.length;
const cand_ai_cnt = cand_ai.length;

// Matches (3×3 grid, normalized)
const match_dir_dir = inter(req_dir,  cand_dir);
const match_dir_imp = inter(req_dir,  cand_imp);
const match_dir_ai  = inter(req_dir,  cand_ai);

const match_imp_dir = inter(req_imp,  cand_dir);
const match_imp_imp = inter(req_imp,  cand_imp);
const match_imp_ai  = inter(req_imp,  cand_ai);

const match_ai_dir  = inter(req_ai,  cand_dir);
const match_ai_imp  = inter(req_ai,  cand_imp);
const match_ai_ai   = inter(req_ai,  cand_ai);

// Missing required (union, normalized)
const miss_req_ = uniq([...miss_req_dir, ...miss_req_imp, ...miss_req_ai]);

// ---------- wilg_score (use upstream if present; else fallback quick compute) ----------
let wilg_score = inItem.wilg_score ?? oa.wilg_score;
if (wilg_score == null) {
  const W_REQ_DIR=3.0, W_REQ_IMP=1.0, W_PREF_DIR=1.0, W_PREF_IMP=0.5, EDU_PENALTY=3.0;

  const req_dir_hits = match_dir_dir.length;
  const req_imp_hits = match_dir_imp.length + match_dir_ai.length;
  const pref_hits    = match_imp_dir.length + match_imp_imp.length + match_imp_ai.length;

  const req_possible = Math.max(1, req_dir.length); // avoid /0
  const base = (req_dir_hits*W_REQ_DIR) + (req_imp_hits*W_REQ_IMP)
             + Math.min(pref_hits*W_PREF_DIR, 0.25*req_possible); // cap preferred at 25% req

  // simple education penalty if JD wants education and candidate has none
  const jd_req_edu = (oa.required_education || inItem.required_education || "").trim();
  const cand_edu   = normArr(oa.candidate_education || inItem.candidate_education || []);
  const penalty = (jd_req_edu && cand_edu.length === 0) ? EDU_PENALTY : 0;

  wilg_score = Math.max(0, Math.min(100, Math.round(100 * (base - penalty) / (req_possible*W_REQ_DIR + 0.25*req_possible))));
}

// ---------- FINAL: EXACT 30 columns (lists joined as single strings) ----------
const row = {
  pair_id,
  job_no,
  job_title,
  company,
  cand_email,
  cand_name,
  cand_phone,

  req_dir:  join1(req_dir),
  req_imp:  join1(req_imp),
  req_ai:   join1(req_ai),

  cand_dir: join1(cand_dir),
  cand_imp: join1(cand_imp),
  cand_ai:  join1(cand_ai),

  req_dir_cnt,
  req_imp_cnt,
  req_ai_cnt,
  cand_dir_cnt,
  cand_imp_cnt,
  cand_ai_cnt,

  // (match_label intentionally omitted to keep total at 30)
  miss_req_: join1(miss_req_),

  match_dir_dir: join1(match_dir_dir),
  match_dir_imp: join1(match_dir_imp),
  match_dir_ai:  join1(match_dir_ai),

  match_imp_dir: join1(match_imp_dir),
  match_imp_imp: join1(match_imp_imp),
  match_imp_ai:  join1(match_imp_ai),

  match_ai_dir:  join1(match_ai_dir),
  match_ai_imp:  join1(match_ai_imp),
  match_ai_ai:   join1(match_ai_ai),

  wilg_score
};

return [{ json: row }];

// n8n Code node — Run Once for Each Item
// Summarize → CSV-ready row (EXACTLY 30 columns)
// - Accepts array fields OR semicolon-joined strings from the previous step
// - Enforces disjoint tiers: imp \= dir; ai \= (dir ∪ imp) for BOTH JD and candidate
// - Rebuilds 3×3 match grid + missing sets
// - Outputs 30 columns (lists joined with "; "); match_label intentionally omitted to keep 30

const row = $json;

// ---------- helpers ----------
const norm = s => String(s || "").toLowerCase().trim();

function parseList(v){
  if (Array.isArray(v)) return v.map(norm).filter(Boolean);
  if (v == null) return [];
  // accept strings like "a; b; c"
  return String(v).split(/\s*;\s*/).map(norm).filter(Boolean);
}
const uniq = a => Array.from(new Set((a||[]).filter(Boolean)));
const diff = (a,b) => {
  const B = new Set((b||[]).map(norm));
  return uniq((a||[]).map(norm).filter(x => !B.has(x)));
};
const inter = (a,b) => {
  const B = new Set((b||[]).map(norm));
  return uniq((a||[]).map(norm).filter(x => B.has(x)));
};
const join1 = arr => uniq(arr).join("; ");

function prefer(...vals){
  for (const v of vals){
    if (v !== undefined && v !== null && String(v) !== "") return String(v);
  }
  return "";
}

// ---------- read inputs (tolerant to arrays or strings) ----------
let req_dir = parseList(row.req_dir);
let req_imp = parseList(row.req_imp);
let req_ai  = parseList(row.req_ai);

let cand_dir = parseList(row.cand_dir);
let cand_imp = parseList(row.cand_imp);
let cand_ai  = parseList(row.cand_ai);

// If short match bucket names exist (from older step), read them, else derive later.
let m_rd_cd  = parseList(row.m_rd_cd);
let m_rd_ci  = parseList(row.m_rd_ci);
let m_rd_cai = parseList(row.m_rd_cai);

let m_ri_cd  = parseList(row.m_ri_cd);
let m_ri_ci  = parseList(row.m_ri_ci);
let m_ri_cai = parseList(row.m_ri_cai);

let m_rai_cd  = parseList(row.m_rai_cd);
let m_rai_ci  = parseList(row.m_rai_ci);
let m_rai_cai = parseList(row.m_rai_cai);

// ---------- enforce disjoint tiers ----------
req_imp = diff(req_imp, req_dir);
req_ai  = diff(req_ai,  [...req_dir, ...req_imp]);

cand_imp = diff(cand_imp, cand_dir);
cand_ai  = diff(cand_ai,  [...cand_dir, ...cand_imp]);

// ---------- rebuild matches if needed; then align to corrected tiers ----------
const needRebuild =
  !m_rd_cd.length && !m_rd_ci.length && !m_rd_cai.length &&
  !m_ri_cd.length && !m_ri_ci.length && !m_ri_cai.length &&
  !m_rai_cd.length && !m_rai_ci.length && !m_rai_cai.length;

if (needRebuild){
  m_rd_cd  = inter(req_dir, cand_dir);
  m_rd_ci  = inter(req_dir, cand_imp);
  m_rd_cai = inter(req_dir, cand_ai);

  m_ri_cd  = inter(req_imp, cand_dir);
  m_ri_ci  = inter(req_imp, cand_imp);
  m_ri_cai = inter(req_imp, cand_ai);

  m_rai_cd  = inter(req_ai, cand_dir);
  m_rai_ci  = inter(req_ai, cand_imp);
  m_rai_cai = inter(req_ai, cand_ai);
} else {
  // Filter buckets to corrected tiers
  m_rd_cd  = inter(m_rd_cd,  req_dir);
  m_rd_ci  = inter(m_rd_ci,  req_dir);
  m_rd_cai = inter(m_rd_cai, req_dir);

  m_ri_cd  = inter(m_ri_cd,  req_imp);
  m_ri_ci  = inter(m_ri_ci,  req_imp);
  m_ri_cai = inter(m_ri_cai, req_imp);

  m_rai_cd  = inter(m_rai_cd,  req_ai);
  m_rai_ci  = inter(m_rai_ci,  req_ai);
  m_rai_cai = inter(m_rai_cai, req_ai);
}

// ---------- recompute missing sets ----------
const miss_req_dir = diff(req_dir, [...m_rd_cd, ...m_rd_ci, ...m_rd_cai]);
const miss_req_imp = diff(req_imp, [...m_ri_cd, ...m_ri_ci, ...m_ri_cai]);
const miss_req_ai  = diff(req_ai,  [...m_rai_cd, ...m_rai_ci, ...m_rai_cai]);

const miss_req_union = uniq([...miss_req_dir, ...miss_req_imp, ...miss_req_ai]);

// ---------- counts ----------
const req_dir_cnt  = req_dir.length;
const req_imp_cnt  = req_imp.length;
const req_ai_cnt   = req_ai.length;
const cand_dir_cnt = cand_dir.length;
const cand_imp_cnt = cand_imp.length;
const cand_ai_cnt  = cand_ai.length;

// ---------- wilg_score (keep if provided; else fallback quick compute) ----------
let wilg_score = row.wilg_score;
if (wilg_score == null || wilg_score === "") {
  const W_REQ_DIR=3.0, W_REQ_IMP=1.0, W_PREF_DIR=1.0, W_PREF_IMP=0.5, EDU_PENALTY=3.0;

  const req_dir_hits = m_rd_cd.length;
  const req_imp_hits = m_rd_ci.length + m_rd_cai.length;

  const pref_hits    = m_ri_cd.length + m_ri_ci.length + m_ri_cai.length;

  const req_possible = Math.max(1, req_dir.length);
