// Ignore boilerplate like "skills with", "experience in/with", "ability to", etc.
const BP_PREFIX = new RegExp(
  String.raw`\b(?:skills?\s+with|experience\s+(?:in|with)|proficiency\s+(?:in|with)|` +
  String.raw`knowledge\s+(?:of|in)|familiarity\s+with|ability\s+to|capab(?:le|ility)\s+(?:of|to)|` +
  String.raw`proven\s+(?:ability|experience)\s+(?:to|in)|demonstrated\s+(?:ability|experience)\s+(?:to|in))\b`,
  "i"
);

// Split lists like "word, excel and tableau"
function splitList(s){
  return String(s)
    .split(/\s*,\s*|\s+and\s+|\s*\/\s*/i)
    .map(t => t.trim())
    .filter(Boolean);
}

