  out.candidate_phone = out.candidate_phone ?? out.cand_phone  ?? out.meta?.phone ?? "";

  // ---- Normalized JD inputs (prefer njd_*) ----
  const jd_req_ai   = uniq(out.njd_must_have_skills     ?? out.njd_required_skills   ?? out.required_skills);
  const jd_pref_ai  = uniq(out.njd_nice_to_have_skills  ?? out.njd_preferred_skills  ?? out.good_to_have);
  const jd_ai_sk    = uniq(out.njd_tools_and_tech       ?? out.tools_and_tech);

  // ---- Normalized Candidate inputs ----
  const cand_direct   = uniq(out.candidate_direct_skills ?? out.cand_skills);
  const cand_inferred = uniq(out.candidate_inferred_skills);
  const cand_soft     = uniq(out.candidate_soft_skills); // kept for downstream matching if needed

  // ---- The 6 JD columns (prematch) ----
  // direct/implied are MATCH concepts; keep as empty placeholders for the loop to populate.
  out.jd_req_direct   = Array.isArray(out.jd_req_direct)   ? out.jd_req_direct   : [];
  out.jd_req_implied  = Array.isArray(out.jd_req_implied)  ? out.jd_req_implied  : [];
  out.jd_req_ai       = jd_req_ai;

  out.jd_pref_direct  = Array.isArray(out.jd_pref_direct)  ? out.jd_pref_direct  : [];
  out.jd_pref_implied = Array.isArray(out.jd_pref_implied) ? out.jd_pref_implied : [];
  out.jd_pref_ai      = jd_pref_ai;

  // Optional: a general JD skills bucket (not counted in the 6, but handy to see)
  out.jd_ai_skills    = Array.isArray(out.jd_ai_skills) ? out.jd_ai_skills : jd_ai_sk;

  // ---- The 3 Candidate columns (prematch) ----
  // required/preferred are MATCH outputs; keep placeholders. AI list = inferred or fallback to direct.
  out.cand_required   = Array.isArray(out.cand_required)  ? out.cand_required  : [];
  out.cand_preferred  = Array.isArray(out.cand_preferred) ? out.cand_preferred : [];
  out.cand_ai_skills  = cand_inferred.length ? cand_inferred : cand_direct;

  // Preserve originals for downstream nodes (non-destructive)
  out.candidate_direct_skills   = cand_direct;
  out.candidate_inferred_skills = cand_inferred;
  out.candidate_soft_skills     = cand_soft;

  out.__node = 'JD_Can_Cross_prematch_v0';
  return { json: out };
});
